using Model.Runtime.Projectiles; using System.Collections.Generic; using UnitBrains.Player; using Utilities; using View;  public class FourthUnitBrain : DefaultPlayerUnitBrain {     public override string TargetUnitName => "Magic Damn";     private float _nextBuffTime;     private float _bufCooldown = 0.5f;      public override List<BaseProjectile> GetProjectiles()     {         List<BaseProjectile> result = new();         return result;     }      public override void Update(float deltaTime, float time)     {         if (time >= _nextBuffTime)         {             _nextBuffTime = time + _bufCooldown;              var friends = GetUnitsInRadius(unit.Config.AttackRange, true);             var buffSystem = ServiceLocator.Get<BuffDebuffSystem>();              foreach (var friend in friends)             {                 if (!buffSystem.HasBuffs(friend))                 {                     var buff = new AttackBuffDebuff(5f, 25f);                     buffSystem.ApplyBuff(friend, buff);                     var vfxView = ServiceLocator.Get<VFXView>();                     vfxView.PlayVFX(friend.Pos, VFXView.VFXType.BuffApplied);                      break;                 }             }         }     } } 